VALUES
  ('social-worker-moex-07150', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在會談的過程中，一個正經歷離婚煎熬與經濟壓力的男性案主向你揭露他曾有一次性侵女兒，作為一個 專業社會工作者，你應如何做？', '["因是會談獲得的資料，需加以保密", "依據法令進行通報", "要案主自己去舉發", "請機構同事通報以便與案主維持關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07151', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關臺灣社區工作的發展，以下那一政府部門於1994年提出「社區總體營造」計畫，獲得社區工作的主 導權？', '["行政院衛生署", "內政部營建署", "行政院文化建設委員會", "內政部社會司"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07152', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '目前對於少數族群的處遇採取跨文化的觀點，以培養跨文化者為目標，在作法上何者不適當？', '["提供跨文化的通譯者、中介者和角色模範", "鼓勵案主縮小外表長相與主流群體的差異程度", "對於不同情境的合宜行為提供回饋、修正和澄清", "提升案主會雙語的程度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07153', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '你的同事因婚姻失和及照顧失智母親而嚴重影響其服務品質，她覺得自己已無法再服務案主而決定結案， 她應如何做？', '["繼續提供服務，因中途遺棄案主是違反倫理的", "跟案主們說明狀況，讓他們自己決定去留", "自己尋求諮商輔導，同時繼續服務案主", "進行結案，但要先花充分時間轉介案主"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07154', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '過去研究顯示，對於非志願案主有效能的實務工作原則不包括下列那一項？', '["聚焦於澄清案主與社工員的角色", "聚焦於示範及鼓勵案主從事利社會的表達與行為", "運用合作式問題解決模式", "聚焦於面質或質疑案主所有的問題與行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07155', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列Skidmore和Thackeray對社會工作存在前提的敘述，何者錯誤？', '["人是複雜而且不平等的", "肯定人重要性", "在人與人互動之中會產生個人、家庭、社區的問題，我們要接受這些問題存在的事實", "經由某種社會工作的方法或處置，可以和緩或解決案主問題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07156', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Johnson（1992）將社會工作價值分為終極價值（ultimate values）、接近價值（proximate values）、工具 價值（instrumental values）。請問下列那一項是屬於工具價值？', '["正義", "尊嚴", "自我實現", "案主自決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07157', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是矯治社會工作者應為的事？', '["向矯治人員學習在日常生活中如何使用權威", "幫助受刑人接受應對自己行為負責的觀念", "幫助受刑人改變生活方式", "花時間進行司法系統的倡導"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07158', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '使用問題解決模式服務非志願案主時，如果案主答應在下次會談前完成任務，然而下次會談時卻發現案 主沒有遵守協議，此時的最適當因應為何？', '["當作沒這件事，加以忽略", "提醒案主在下次會談前要完成，或重訂新完成期限", "與案主討論沒有完成任務的原因", "帶案主一起去執行任務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07159', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何種狀況違反社會工作的保密原則？', '["提供高三女生受虐或被疏忽的資訊給責任單位", "提供高三男生威脅傷害其他學生的資訊給校長", "提供高三男生意圖自殺的資訊給輔導主任", "提供高三女生與其男友發生性行為的資訊給其父母"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
